// @ts-check
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { defineConfig } from 'astro/config';
import starlight from '@astrojs/starlight';

// Sidebar is generated by scripts/sync-docs.mjs (runs on predev/prebuild).
const sidebarUrl = new URL('./src/generated/sidebar.json', import.meta.url);
let sidebar = [];
try {
  sidebar = JSON.parse(readFileSync(fileURLToPath(sidebarUrl), 'utf8'));
} catch {
  // sync-docs has not run yet; fall back to autogeneration so the config still loads.
  sidebar = [{ label: 'Documentation', autogenerate: { directory: '.' } }];
}

export default defineConfig({
  site: 'https://lattice.example',
  integrations: [
    starlight({
      title: 'Lattice',
      description:
        'Documentation for Lattice — a fast, local-first, open-native workspace built from real files.',
      tagline: 'The open information studio.',
      logo: {
        src: './src/assets/lattice-mark.svg',
        alt: 'Lattice',
        replacesTitle: false,
      },
      customCss: [
        '@fontsource-variable/fraunces',
        '@fontsource-variable/space-grotesk',
        '@fontsource-variable/jetbrains-mono',
        './src/styles/theme.css',
        './src/styles/starlight.css',
      ],
      // Dark-only: force the theme so docs match the marketing look.
      // (light/dark toggle removed via disableThemeSelector below is not a real
      // option; we instead pin defaultColorScheme through CSS + head.)
      social: [
        { icon: 'github', label: 'GitHub', href: 'https://github.com' },
      ],
      sidebar,
      components: {
        // Single coherent dark theme: remove the light/dark toggle.
        ThemeSelect: './src/components/EmptyThemeSelect.astro',
      },
      head: [
        // Force dark color scheme for the docs section to match the site.
        {
          tag: 'meta',
          attrs: { name: 'color-scheme', content: 'dark' },
        },
      ],
      pagination: true,
      lastUpdated: false,
      editLink: undefined,
    }),
  ],
});
